import React, { useEffect, useState, createContext, useContext } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'AUTHENTICATED';
const rnBiometrics = new ReactNativeBiometrics();

const AuthContext = createContext(null);

const useAuth = () => useContext(AuthContext);

const AuthProvider = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState(null);

  useEffect(() => {
    bootstrapAuth();
  }, []);

  const bootstrapAuth = async () => {
    try {
      const [storedAuth, biometricResult] = await Promise.all([
        AsyncStorage.getItem(AUTH_FLAG_KEY),
        rnBiometrics.isSensorAvailable(),
      ]);

      if (biometricResult?.available) {
        setBiometricAvailable(true);
        setBiometricType(biometricResult.biometryType || null);
      } else {
        setBiometricAvailable(false);
        setBiometricType(null);
      }

      if (storedAuth === 'true') {
        setIsAuthenticated(true);
      }
    } catch (e) {
      setBiometricAvailable(false);
      setBiometricType(null);
    } finally {
      setIsLoading(false);
    }
  };

  const persistAuthenticated = async () => {
    await AsyncStorage.setItem(AUTH_FLAG_KEY, 'true');
    setIsAuthenticated(true);
  };

  const loginWithPassword = async (username, password) => {
    if (!username?.trim() || !password?.trim()) {
      Alert.alert('Login failed', 'Please enter username and password.');
      return false;
    }

    await persistAuthenticated();
    return true;
  };

  const loginWithBiometrics = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();

      if (!available) {
        Alert.alert('Biometrics unavailable', 'Use password login on this device.');
        return false;
      }

      const promptMessage =
        biometryType === ReactNativeBiometrics.TouchID
          ? 'Authenticate with Touch ID'
          : biometryType === ReactNativeBiometrics.FaceID
          ? 'Authenticate with Face ID'
          : 'Authenticate with Biometrics';

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await persistAuthenticated();
        return true;
      }

      return false;
    } catch (e) {
      Alert.alert('Authentication failed', 'Biometric verification was not successful.');
      return false;
    }
  };

  const logout = async () => {
    await AsyncStorage.removeItem(AUTH_FLAG_KEY);
    setIsAuthenticated(false);
  };

  return (
    <AuthContext.Provider
      value={{
        isLoading,
        isAuthenticated,
        biometricAvailable,
        biometricType,
        loginWithPassword,
        loginWithBiometrics,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

const SplashScreen = () => (
  <View style={styles.centered}>
    <ActivityIndicator size="large" />
    <Text style={styles.loadingText}>Loading...</Text>
  </View>
);

const HomeScreen = () => {
  const { logout, biometricType } = useAuth();

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text style={styles.subtitle}>
        You are authenticated
        {biometricType ? ` with ${biometricType}.` : '.'}
      </Text>

      <TouchableOpacity style={styles.button} onPress={logout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

const LoginScreen = () => {
  const { biometricAvailable, biometricType, loginWithBiometrics, loginWithPassword } = useAuth();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const handlePasswordLogin = async () => {
    setSubmitting(true);
    try {
      await loginWithPassword(username, password);
    } finally {
      setSubmitting(false);
    }
  };

  const handleBiometricLogin = async () => {
    setSubmitting(true);
    try {
      await loginWithBiometrics();
    } finally {
      setSubmitting(false);
    }
  };

  const biometricLabel =
    biometricType === ReactNativeBiometrics.FaceID
      ? 'Continue with Face ID'
      : biometricType === ReactNativeBiometrics.TouchID
      ? 'Continue with Touch ID'
      : 'Continue with Biometrics';

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricAvailable ? (
        <>
          <TouchableOpacity
            style={[styles.button, submitting && styles.buttonDisabled]}
            onPress={handleBiometricLogin}
            disabled={submitting}
          >
            <Text style={styles.buttonText}>{biometricLabel}</Text>
          </TouchableOpacity>

          <Text style={styles.orText}>OR</Text>
        </>
      ) : (
        <Text style={styles.subtitle}>
          Biometrics not available on this device. Use password login.
        </Text>
      )}

      <TextInput
        style={styles.input}
        placeholder="Username"
        autoCapitalize="none"
        value={username}
        onChangeText={setUsername}
        editable={!submitting}
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
        editable={!submitting}
      />

      <TouchableOpacity
        style={[styles.button, submitting && styles.buttonDisabled]}
        onPress={handlePasswordLogin}
        disabled={submitting}
      >
        <Text style={styles.buttonText}>{submitting ? 'Please wait...' : 'Login with Password'}</Text>
      </TouchableOpacity>

      <Text style={styles.footerText}>
        {Platform.OS === 'ios'
          ? 'Face ID / Touch ID supported when available.'
          : 'Fingerprint / device biometrics supported when available.'}
      </Text>
    </View>
  );
};

const AppContent = () => {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) {
    return <SplashScreen />;
  }

  if (isAuthenticated) {
    return <HomeScreen />;
  }

  return <LoginScreen />;
};

export default function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

